request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?taskName ?allParticipants WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "1dccc40d34ef40f9b36123e2fbca1a63" .
  ?def tai:belongsTo ?model .
  ?choreo tai:belongsTo ?def .
  ?task a bboExt:ChoreographyTask .
  ?task tai:belongsTo ?choreo .
  ?task bbo:name ?taskName .

  # Get all participant names for this task (via all participants in the choreography)
  {
    SELECT ?task (GROUP_CONCAT(DISTINCT ?pName; separator=", ") AS ?allParticipants) WHERE {
      ?task a bboExt:ChoreographyTask .
      ?task bbo:id ?taskId .
      ?mf a bboExt:MessageFlow .
      {
        ?mf bboExt:sourceRef ?srcRef .
        FILTER(STRENDS(STR(?task), ?srcRef))
      } UNION {
        ?mf bboExt:targetRef ?tgtRef .
        FILTER(STRENDS(STR(?task), ?tgtRef))
      }
      ?part a bboExt:Participant .
      ?part bbo:name ?pName .
    }
    GROUP BY ?task
  }
}
LIMIT 25
